gested'=>$i%4===0,'is_active'=>true]);}Article::truncate();foreach(['راهنمای خرید گوشی هوشمند','چطور لپ‌تاپ مناسب انتخاب کنیم؟','مزایای گجت‌های خانه هوشمند'] as $i=>$title){$image=ShopImage::pathFor('article','article-'.($i+1));ShopImage::ensureSvg($image,$title,'article',$i+1);Article::create(['title'=>$title,'slug'=>'article-'.($i+1),'image'=>$image,'excerpt'=>'نکات کاربردی برای خرید بهتر محصولات دیجیتال.','content'=>'در این مقاله معیارهای مهم انتخاب، بودجه‌بندی، گارانتی و تجربه کاربری را بررسی می‌کنیم.','author_id'=>$admin->id,'published_at'=>now(),'is_active'=>true,'is_published'=>true,'show_in_home'=>true]);}foreach([['hero','اسلایدر اصلی',''],['categories','دسته‌بندی‌های محبوب',''],['featured_products','پیشنهادهای شگفت‌انگیز','محصولات منتخب با تخفیف ویژه'],['best_sellers','پرفروش‌ترین محصولات',''],['latest_products','جدیدترین محصولات',''],['articles','مجله فروشگاه','']] as $i=>$sec)HomeSection::updateOrCreate(['key'=>$sec[0]],['title'=>$sec[1],'subtitle'=>$sec[2],'sort_order'=>$i,'is_active'=>true]);}}
